# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def calculate_discount(user_role):
    if user_role == 'enterprise':
        return 0.30
    elif user_role == 'premium':
        return 0.15
    else:
        return 0.00

def process_payment(cart_total, discount_percentage):
    discounted_amount = cart_total * discount_percentage
    final_amount = cart_total - discounted_amount
    # Simulate payment processing
    print(f"Processing payment of {final_amount}")
    return final_amount

def payment_processing_function(user, cart_items, payment_details):
    user_role = user['role']
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    discount_percentage = calculate_discount(user_role)
    discounted_cart_total = process_payment(cart_total, discount_percentage)
    return {'user': user, 'cart_items': cart_items, 'payment_details': payment_details, 'discounted_amount': cart_total - discounted_cart_total}

# Example usage:
user = {'role': 'premium'}
cart_items = [{'price': 100, 'quantity': 2}, {'price': 50, 'quantity': 1}]
payment_details = {'method': 'credit_card', 'card_number': '**** **** **** 1234'}
result = payment_processing_function(user, cart_items, payment_details)
print(result)